def load_error_code_file(file_name):
	tmp = dict()
	if os.path.exists(file_name):
		with open(file_name, "r") as file:
			reader = csv.reader(file)
			for row in reader:
				tmp[str(row[0])] = row[1]
		return tmp
	return False

