class JsonConfig(object):

    def __init__(self, strPath="", strType="json"):
        self.Type = strType
        self.Path = strPath
        self.Config = {}
        self.Statu = False
        self.load()

    def load(self):
        bRet = True
        try:
            if self.Type.lower() == "json":
                # add path check here
                f = open(self.Path, 'r')
                self.Config = json.load(f)
                f.close()
        except Exception as e:
            print ("cBruceConfig Get Exception {}".format(str(e)))
            bRet = False
        self.Statu = bRet
        return bRet
    
    def GetConfig(self, strKey):
        strRet = None
        if self.Statu:
            strRet = self.Config.get(strKey)
        else:
            print ("cBruceConfig Get {} from {}".format(strKey, self.Config))
        return strRet
    
    def SetConfig(self, strKey, value):

        self.Config[strKey] = value
        # self.Config.setdefault(strKey, value)
        return True
        
	
    def SaveConfig(self):
        if not os.path.exists(self.Path):
            return False
        with open(self.Path, 'w', encoding='utf-8') as f:
            json.dump(self.Config, f, ensure_ascii=False, indent=4, sort_keys=False)
        return True

