def get_mes_status(ghinfo=gh_info):
	ghinfo.load()
	return ghinfo.GetConfig(ICT_MES_DATA_KEY.MES_STATUS)

def save_mes_status(isenable=True, ghinfo=gh_info):
	ghinfo.load()
	ghinfo.SetConfig(ICT_MES_DATA_KEY.MES_STATUS, isenable)
	ghinfo.SaveConfig()
	return True

class MES(object):

	PASS = 200

	def __init__(self):
		self.url = MES_URL
		self.station_type = STATION_TYPE
		self.station_id = STATION_ID
		self.station_num = STATION_NUM

	def post(self, query_key, data, headers=None):
		query_url = self.url + query_key
		if headers:
			return requests.post(query_url, files=data, headers=headers)
		return requests.post(query_url, data=data)
	
	def get(self, query_key, params):
		query_url = self.url + query_key
		return requests.get(query_url, params=params)
	
	def parse_response(self, response, key=None):
		if response.status_code == MES.PASS:
			ret_json = json.loads(ElementTree.fromstring(response.text).text)
			if key:
				return ret_json[key]
			return ret_json
		return None
	
	def format_data(self):
		pass


class MesSN(MES):
	_dict = {
			ICT_SN_KEY.TCMD: TCMD,
			ICT_SN_KEY.SN: None,
			ICT_SN_KEY.TYPE: "0",
			ICT_SN_KEY.TSID: STATION_ID,
			ICT_SN_KEY.EMPNO: None
	}

	def __init__(self, empno="Test user",params_prefix="param"):
		super().__init__()
		self._empno = empno
		self.params_prefix = params_prefix


	def get_mac(self,sn):
		_dict = MesSN._dict
		_dict[ICT_SN_KEY.TCMD] = TCMD
		_dict[ICT_SN_KEY.SN] = sn
		_dict[ICT_SN_KEY.EMPNO] = self._empno
		_json_data = json.dumps(_dict)
		_data = {
			self.params_prefix: _json_data
		}
		response = self.post(ICT_SN_KEY.GETMACBYSN,_data)
		parse_response =  self.parse_response(response)
		print(parse_response,type(parse_response))
		if parse_response:
			result = parse_response.get("Result")
			info = parse_response.get("Info")
			if result == "OK":
				info = parse_response.get("Info")
				# mac = re.findall(r"MACCODE=(\w+)", info)[0]
				if info:
					return info,_data
			else:
				return False, "info"
		return False, "Get MAC from MES failed"
		
	

class UploadMES(MES):

	_dict = {
			ICT_MES_DATA_KEY.COMMAND: None,
			ICT_MES_DATA_KEY.SERIAL_NUMBER: None,
			ICT_MES_DATA_KEY.VERSION: "V1.0",
			ICT_MES_DATA_KEY.TERMINAL_NAME: STATION_ID,
	}

	def __init__(self, empno="Test user",params_prefix="strjson"):
		super().__init__()
		self._empno = empno
		self.params_prefix = params_prefix
	
	def check_data(self, sn):
		# if NOPDCA:
		# 	return "--SKIP--", "--SKIP--NOPDCA"
		_dict = UploadMES._dict
		_dict[ICT_MES_DATA_KEY.COMMAND] = ICT_MES_DATA_KEY.CHECK_DATA
		_dict[ICT_MES_DATA_KEY.SERIAL_NUMBER] = sn

		_json_data = json.dumps(_dict)
		_data = {
			self.params_prefix: _json_data
		}
		print(_data)
		response = self.post(ICT_MES_DATA_KEY.CHECK_DATA,_data)
		if response.status_code == MES.PASS:
			parse_response = self.parse_response(response)
			return True,parse_response
		else:
			return  False,"check data from mes failed,status_code:{}".format(response.status_code)

	def send_data(self, sn, test_data, test_result, fixture_id="", error_code="", error_msg="", header=None):
		# if NOPDCA:
		# 	return "--SKIP--", "--SKIP--NOPDCA"
		assert isinstance(test_data, list)
		if len(test_data) > 0:
			assert isinstance(test_data[0], dict)
		_dict = UploadMES._dict
		_dict[ICT_MES_DATA_KEY.COMMAND] = ICT_MES_DATA_KEY.SEND_DATA
		_dict[ICT_MES_DATA_KEY.SERIAL_NUMBER] = sn
		_dict[ICT_MES_DATA_KEY.TEST_RESULT] = test_result
		_dict[ICT_MES_DATA_KEY.ERROR_CODE] = error_code
		_dict[ICT_MES_DATA_KEY.ERROR_MSG] = error_msg
		_dict[ICT_MES_DATA_KEY.LOG_FILE] = LOG_FILE
		_dict[ICT_MES_DATA_KEY.EMPNO] = self._empno
		_dict[ICT_MES_DATA_KEY.JIG_NO] = fixture_id
		_dict[ICT_MES_DATA_KEY.TEST_DATA] = test_data
		# add some news
		_json_data = json.dumps(_dict)
		_data = {
			self.params_prefix: _json_data
		}
		response = self.post(ICT_MES_DATA_KEY.SEND_DATA,_data)
		if response.status_code == MES.PASS:
			parse_response = self.parse_response(response)
			return True, parse_response
		else:
			return False, "check data from mes failed,status_code:{}".format(response.status_code)

	def get_error_code(self, filename, item_name):
		filename = testercofig_path + filename
		dt = load_error_code_file(filename)
		if dt:
			return dt.get(item_name, None)
		return None


